import{_ as e,o as a,c as o,ah as r}from"./chunks/framework.C8Zd3T50.js";const l=JSON.parse('{"title":"Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"dp/index.md","filePath":"dp/index.md"}'),s={name:"dp/index.md"};function i(n,t,d,p,u,c){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h1><p>A great deal in os384 is working, but there is a laundrylist of gaps. We&#39;d like to think we have a rough idea of what those are and roughly how to go about addressing them. This section collects draft design documents that attempt to capture that.</p><hr><h2 id="dp-01-root-security" tabindex="-1">DP-01: Root Security <a class="header-anchor" href="#dp-01-root-security" aria-label="Permalink to &quot;DP-01: Root Security&quot;">​</a></h2><p>os384 holds &quot;trust as little as possible&quot; as a design ethos, but is missing is a coherent, end-to-end strategy for <em>root security</em> — the chain of trust from &quot;a user opens a browser&quot; through to &quot;os384 code is executing the user&#39;s intent.&quot;</p><p>This document maps classical security problems (code distribution integrity, bootstrap trust, transport trust, key management) onto os384&#39;s current state, identifies gaps, derives design principles, and offers a straw man proposal centred on signed page envelopes, a standalone verifier artifact, SRI-pinned entry HTML, and trust tiers ranging from default-web to self-hosted.</p><p><a href="/BhoW6b/dp/DP-01-Root-Security.html">Read DP-01: Root Security →</a></p>',7)])])}const m=e(s,[["render",i]]);export{l as __pageData,m as default};
